@@
   // Select the best VF among a fixed set of candidate VFs.
   const VectorizationFactor &BestFactor = *std::min_element(
       Factors.begin(), Factors.end(),
       [&](const VectorizationFactor &VF1, const VectorizationFactor &VF2) {
         return VF1.Cost < VF2.Cost;
